sql:
SELECT AVG(budget) AS average_budget
FROM productions
WHERE genre = 'Action' AND year >= 2020;

SELECT AVG(budget) AS average_budget, COUNT(*) AS total_films
FROM productions
WHERE genre = 'Action';

SELECT title
FROM productions
WHERE production_id = 1;

external_knowledge:
- Captains steering their fleet: directors overseeing their productions;
- Shining horizons of acclaim: high ratings;
- Cinematic excellence: film industry's quality standards;
- Fleets' average navigational stars: average ratings of directors' productions.

sql:
SELECT title, year
FROM productions
ORDER BY year DESC;

SELECT AVG(rating) AS average_rating
FROM productions
WHERE status = 'released';
